@namespace sv_75ff32d1e063415cab87e7bcae3bb188.Components.Pages.Apply

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var css = step == CurrentStep ? "step active"
                    : step < CurrentStep ? "step completed"
                    : "step future";
            <li class="@css"
                role="button"
                @onclick="() => OnStepClick(step)">
                <span class="step-circle">
                    @if (step < CurrentStep)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </span>
                <span class="step-label">@StepNames[step]</span>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnStepClicked { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    padding: 0;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

.step-list::before {
    content: "";
    position: absolute;
    top: 18px;
    left: 40px;
    right: 40px;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    position: relative;
    z-index: 1;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    margin-bottom: 0.5rem;
    border: 2px solid #dee2e6;
    background: white;
    color: #adb5bd;
    transition: all 0.2s;
}

.step-label {
    font-size: 0.8rem;
    text-align: center;
    color: #adb5bd;
    white-space: nowrap;
}

.step.active .step-circle {
    background: #0d6efd;
    border-color: #0d6efd;
    color: white;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-circle {
    background: #198754;
    border-color: #198754;
    color: white;
    cursor: pointer;
}

.step.completed .step-label {
    color: #198754;
    cursor: pointer;
}

.step.completed:hover .step-circle {
    background: #157347;
    border-color: #157347;
}

.step.future {
    pointer-events: none;
}

@namespace sv_75ff32d1e063415cab87e7bcae3bb188.Components.Pages.Apply
@using sv_75ff32d1e063415cab87e7bcae3bb188.Models

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control @(EmailError is not null ? "is-invalid" : "")"
           @bind="Model.Email" @bind:event="oninput" />
    @if (EmailError is not null)
    {
        <div class="invalid-feedback">@EmailError</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput"></textarea>
</div>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public PersonalInfoModel Model { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ValidationError;
    private string? EmailError;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ValidationError = null;
        EmailError = null;

        if (!Model.IsValid())
        {
            ValidationError = "Please fill in all required fields.";
            return;
        }

        IsValidating = true;
        try
        {
            var isEmailValid = await ValidateEmail(Model.Email);
            if (!isEmailValid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            IsValidating = false;
        }
    }
}

