@namespace sv_75ff32d1e063415cab87e7bcae3bb188.Components.Pages.Apply
@using sv_75ff32d1e063415cab87e7bcae3bb188.Models

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index"
                   CanRemove="Entries.Count > 1"
                   OnRemove="() => RemoveEntry(index)" />
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    <span class="me-1">+</span> Add Another Position
</button>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired]
    public List<WorkEntryModel> Entries { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ValidationError = null;

        if (Entries.Any(e => !e.IsValid()))
        {
            ValidationError = "Please fill in required fields (company, title, start date) for all positions.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

