@namespace sv_75ff32d1e063415cab87e7bcae3bb188.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12"
              @bind="CoverLetter" @bind:event="oninput"
              maxlength="@MaxLength"></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

@if (ValidationError is not null)
{
    <div class="alert alert-danger">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired]
    public string CoverLetter { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> CoverLetterChanged { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private async Task HandleNext()
    {
        ValidationError = null;
        await CoverLetterChanged.InvokeAsync(CoverLetter);
        await OnNext.InvokeAsync();
    }
}

