@page "/apply"
@namespace sv_75ff32d1e063415cab87e7bcae3bb188.Components.Pages.Apply
@using sv_75ff32d1e063415cab87e7bcae3bb188.Models
@using sv_75ff32d1e063415cab87e7bcae3bb188.Services
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (_submittedId.HasValue)
    {
        <div class="alert alert-success text-center">
            <h4 class="alert-heading">Application Submitted!</h4>
            <p>Your application has been received. Your application ID is:</p>
            <p class="display-6 fw-bold">@_submittedId</p>
            <p class="mb-0">Please save this number for your records.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep" OnStepClicked="GoToStep" />

        @switch (_currentStep)
        {
